window.imprimirRecibos = function () {

  const precio = document.getElementById("precio")?.value || "";
  const fecha = new Date().toLocaleDateString("es-ES");

  const lista = (todasLasPersonas || [])
  .filter(p => p && p.nombreCompleto)
  .sort((a, b) =>
    (a.direccionCompleta || "").localeCompare(
      (b.direccionCompleta || ""),
      "es",
      { numeric: true, sensitivity: "base" }
    )
  );
  let html = `
  <html>
  <head>
    <style>

      @page {
        size: A4;
        margin: 0;
      }

      body {
        font-family: Arial;
        margin: 0;
      }

      .pagina {
        width: 210mm;
        height: 297mm;
        page-break-after: always;
      }

      .recibo {
        height: 99mm;
        box-sizing: border-box;
        border-bottom: 1px dashed #000;
        padding: 6mm;
        display: flex;
        justify-content: space-between;
          line-height: 1.4;
      }

      .izq { width: 65%; }
      .der { width: 30%; text-align: center; }

      .nombre {
        font-weight: bold;
        font-size: 18px;
        margin-bottom: 8px;
        letter-spacing: 0.5px;
      }

      .direccion { font-size: 14px; }

      .texto {
        margin-top: 1px;
        font-size: 14px;
      }

      .fecha {
        margin-top: 8px;
        font-size: 13px;
      }
.imagen {
  width: 100%;
  height: 100%;
  object-fit: contain;
}
  .der {
  width: 30%;
}

.izq {
  width: 65%;
}   

     
      }

    </style>
  </head>
  <body>
  `;

  // 👉 Agrupar en páginas de 3
  for (let i = 0; i < lista.length; i += 3) {

    html += `<div class="pagina">`;

    lista.slice(i, i + 3).forEach((p) => {

      html += `
      <div class="recibo">

        <div class="izq">
          <div class="nombre">${p.nombreCompleto}</div>

          <div class="direccion">${p.direccionCompleta || ""}</div>
          <div class="direccion">${p.codigoPostal || ""} ${p.poblacion || ""}</div>
          <div class="direccion">${p.provincia || ""}</div>

          <div class="texto">
            CUOTA ${new Date().getFullYear()} COFRADÍA SAN CRISTOBAL<br>
            CANTIDAD: ${precio ? precio + " €" : "________"}
          </div>

          <div class="fecha">
            Fecha: ${fecha}
          </div>

          <div class="texto">
            FIRMADO: ____________________
          </div>
        </div>

        <div class="der">
  <img src="data:image/png;base64," class="imagen">
</div>

      </div>
      `;
    });

    html += `</div>`;
  }

  html += `</body></html>`;

  const win = window.open("", "_blank");
  win.document.write(html);
  win.document.close();

  setTimeout(() => {
    win.print();
  }, 500);
};
