// ==============================
// 📄 PDF CON jsPDF + IMÁGENES
// ==============================
window.generarPDF = function (lista) {

  const { jsPDF } = window.jspdf;

  const doc = new jsPDF({
    unit: "mm",
    format: "a4"
  });

  const precio = document.getElementById("precio")?.value || "";
  const fecha = new Date().toLocaleDateString("es-ES");

  // 🔥 TU IMAGEN (logo + firma juntos)
  const imagenBase64 = `data:image/png;base64,`;
 let y = 10;
  let contador = 0;

  lista.forEach((p) => {

    if (contador === 3) {
      doc.addPage();
      y = 10;
      contador = 0;
    }

    doc.rect(10, y, 190, 85);

    doc.setFontSize(12);
    doc.text(p.nombreCompleto || "", 15, y + 10);

    doc.setFontSize(10);
    doc.text(p.direccionCompleta || "", 15, y + 18);
    doc.text(`${p.codigoPostal || ""} ${p.poblacion || ""}`, 15, y + 24);
    doc.text(p.provincia || "", 15, y + 30);

    doc.text(`CUOTA ${new Date().getFullYear()}`, 15, y + 42);
    doc.text(`CANTIDAD: ${precio ? precio + " €" : "______"}`, 15, y + 48);

    doc.text(`Fecha: ${fecha}`, 15, y + 58);
    doc.text("FIRMADO: ____________________", 15, y + 70);

    doc.addImage(imagenBase64, "PNG", 135, y + 5, 55, 75);

    y += 95;
    contador++;

    if (contador < 3) {
      doc.setLineDash([2, 2]);
      doc.line(10, y - 5, 200, y - 5);
      doc.setLineDash([]);
    }

  });

  doc.save("recibos_cofradia.pdf");
};

  window.descargarRecibosPDF = function () {
  const lista = obtenerListaOrdenada();
  generarPDF(lista);
};

